"""Исключения модуля yandex_ocr."""from __future__ import annotationsclass YandexOCRError(Exception):    """Базовое исключение модуля Yandex OCR."""    def __init__(self, message: str, cause: Exception | None = None) -> None:        super().__init__(message)        self.cause = causeclass YandexOCRAuthError(YandexOCRError):    """Ошибка аутентификации (401, 403, неверный Api-Key)."""class YandexOCRTransportError(YandexOCRError):    """Сетевая/транспортная ошибка (таймаут, соединение)."""class YandexOCRResponseError(YandexOCRError):    """Невалидный или неожиданный ответ API."""